={
  "contents": [{
    "parts": [
      {"fileData": {"mimeType": "{{ $json.file.mimeType }}", "fileUri": "{{ $json.file.uri }}"}},
      {"text": "Analyze this meeting recording. Provide:\n1. Meeting summary (3-5 paragraphs)\n2. Key decisions made\n3. Action items with assignees if mentioned\n4. Follow-up topics\n\nOutput as JSON with keys: summary, decisions (array), actionItems (array of {task, assignee, deadline}), followUps (array)"}
    ]
