parameters.jsCode:
// Parse Gemini response
var response = $input.first().json;
var text = '';
try { text = response.candidates[0].content.parts[0].text; } catch(e) { text = '{}'; }
var parsed;
try { parsed = JSON.parse(text); } catch(e) { parsed = {summary: text, decisions: [], actionItems: [], followUps: []}; }
var meetingTitle = $('Upload meeting recording').first().json['Meeting Title'] || 'Untitled meeting';
var actionList = (parsed.actionItems || []).map(function(a) { return '- [ ] ' + (a.task || a) + (a.assignee ? ' (@' + a.assignee + ')' : ''); }).join('\n');
return { json: { title: meetingTitle, summary: parsed.summary || '', decisions: (parsed.decisions || []).join('\n- '), actionItems: actionList, followUps: (parsed.followUps || []).join('\n- '), date: new Date().toISOString() } };
